<?php
namespace App\Http\Controllers\Admin;
use App\Http\Controllers\Controller; use App\Services\Admin\ActivityLogger; use Illuminate\Http\Request; use Illuminate\Support\Facades\Auth; use Illuminate\Support\Facades\Password; use Illuminate\Support\Facades\Hash; use Illuminate\Support\Str;
class AuthController extends Controller { public function loginForm(){return view('admin.auth.login');} public function login(Request $r, ActivityLogger $l){$data=$r->validate(['email'=>'required|email','password'=>'required']); if(Auth::attempt($data,$r->boolean('remember'))){$r->session()->regenerate(); $l->log('login','User logged in'); return redirect()->route('admin.dashboard');} return back()->withErrors(['email'=>'Invalid credentials.']);} public function logout(Request $r, ActivityLogger $l){$l->log('logout','User logged out'); Auth::logout(); $r->session()->invalidate(); $r->session()->regenerateToken(); return redirect()->route('login');} public function forgot(){return view('admin.auth.forgot-password');} public function email(Request $r){$r->validate(['email'=>'required|email']); Password::sendResetLink($r->only('email')); return back()->with('status','Password reset link sent.');} public function reset(string $token){return view('admin.auth.reset-password',compact('token'));} public function updatePassword(Request $r){$r->validate(['token'=>'required','email'=>'required|email','password'=>'required|confirmed|min:8']); $status=Password::reset($r->only('email','password','password_confirmation','token'),function($user,$password){$user->forceFill(['password'=>Hash::make($password),'remember_token'=>Str::random(60)])->save();}); return $status===Password::PASSWORD_RESET?redirect()->route('login')->with('status','Password reset.'):back()->withErrors(['email'=>__($status)]);} }
